using namespace std;

#define ll long long
#define pb push_back
#define vi vector<int>
#define vvi vector<vector<int>>
#define pii pair<int, int>

const int MAX_N = 1e5 + 5;
vector<int> adj[MAX_N];
bool visited[MAX_N];

void dfs(int node, int parent, bool &has_cycle, vector<int> &cycle_edges) {
    visited[node] = true;
    for (int neighbor : adj[node]) {
        if (!visited[neighbor]) {
            dfs(neighbor, node, has_cycle, cycle_edges);
        } else if (neighbor != parent) {
            // Backedge found, cycle detected
            has_cycle = true;
            int curr = node;
            while (curr != neighbor) {
                cycle_edges.pb(curr);
                curr = parent[curr];
            }
            cycle_edges.pb(neighbor);
            cycle_edges.pb(node);
        }
    }
}

void find_cycles(vvi &cycles) {
    memset(visited, false, sizeof(visited));
    for (int i = 1; i <= n; ++i) {
        if (!visited[i]) {
            vector<int> cycle_edges;
            bool has_cycle = false;
            dfs(i, -1, has_cycle, cycle_edges);
            if (has_cycle) {
                cycles.pb(cycle_edges);
            }
        }
    }
}

void solve() {
    int n, m;
    cin >> n >> m;
    for (int i = 0; i < m; ++i) {
        int u, v;
        cin >> u >> v;
        adj[u].pb(v);
        adj[v].pb(u);
    }

    vvi cycles;
    find_cycles(cycles);

    cout << 2 * cycles.size() << endl;
    for (auto &cycle : cycles) {
        int len = cycle.size();
        for (int i = 0; i < len - 1; ++i) {
            cout << cycle[i] << ' ' << cycle[i + 1] << ' ' << cycle.back() << '\n';
        }
    }
}

