int minSnowDrifts(int n, vector<pair<int, int>>& drifts) {
    set<int> rows, cols;
    for (const auto& d : drifts) {
        rows.insert(d.first);
        cols.insert(d.second);
    }
    return max(rows.size(), cols.size());
}

