const int MX = (1 << 18), MXL = 18;
int sz[MX], P[MX], val[MX];

void init(int N) {
    for (int j = 1; j <= N; j++)
        sz[j] = 1, P[j] = j;
}

int find_(int x) {
    if (x != P[x]) P[x] = find_(P[x]);
    return P[x];
}

bool merge_(int x, int y) {
    int px = find_(x), py = find_(y);
    if (px == py) return false;
    if (sz[px] < sz[py]) swap(px, py);
    P[py] = px;
    sz[px] += sz[py];
    return true;
}

int n, QN, m;
int depth[MX], dp[MXL][MX], par[MXL][MX];
vector<pair<int, int>> v[MX];

void Pdfs(int x, int p) {
    int nxt, C, sz = v[x].size();
    for (int j = 0; j < sz; j++) {
        nxt = v[x][j].first, C = v[x][j].second;
        if (nxt == p) continue;
        depth[nxt] = depth[x] + 1;
        par[0][nxt] = x;
        dp[0][nxt] = C;
        Pdfs(nxt, x);
    }
}

int Merge(int a, int b) {
    if (a == -1) return b;
    if (b == -1) return a;
    if (val[a] > val[b]) return a;
    else return b;
}

void process() {
    for (int j = 1; j < MXL; j++)
        for (int i = 1; i <= n; i++) {
            par[j][i] = par[j - 1][par[j - 1][i]];
            dp[j][i] = Merge(dp[j - 1][i], dp[j - 1][par[j - 1][i]]);
        }
}

int Kth(int x, int K) {
    int node = x;
    for (int j = 0; j < MXL; j++)
        if ((K & (1 << j)))
            node = par[j][node];
    return node;
}

int LCA(int a, int b) {
    if (a == b) return a;
