#include <bits/stdc++.h>
using namespace std;

#define ll long long
const int N = 2e5 + 7;
int n, m, S;
ll w[N], c[N];
vector<pair<int, int>> g[N];
pair<ll, int> edges[N];

struct DSU {
    vector<int> p;
    DSU(int n) : p(n) { iota(p.begin(), p.end(), 0); }
    int find(int v) { return p[v] == v ? v : p[v] = find(p[v]); }
    void merge(int u, int v) { p[find(u)] = find(v); }
};

bool cmp(const pair<ll, int>& a, const pair<ll, int>& b) {
    return a.first / (double)b.second < b.first / (double)a.second;
}

void solve() {
    cin >> n >> m >> S;
    for (int i = 1; i <= m; ++i) cin >> w[i] >> c[i];
    for (int i = 0; i < m; ++i) {
        int a, b;
        cin >> a >> b;
        edges[i] = {w[i], i};
        g[a].push_back({b, i});
        g[b].push_back({a, i});
    }

    sort(edges, edges + m, cmp);
    DSU dsu(n + 1);
    vector<bool> used(m, false);
    ll total_cost = 0;
    ll total_dis = 0;

    for (int i = 0; i < m && dsu.find(1) != dsu.find(n); ++i) {
        int e = edges[i].second;
        auto [x, y] = g[e][0];
        if (dsu.find(x) != dsu.find(y)) {
            dsu.merge(x, y);
            used[e] = true;
            total_cost += c[e];
            total_dis -= w[e];
        }
    }

    if (total_cost > S) {
        // Adjust dissatisfaction levels
        for (int i = m - 1; i >= 0 && total_cost > S; --i) {
            if (!used[i]) {
                auto [x, y] = g[i][0];
                if (dsu.find(x) != dsu.find(y)) {
                    dsu.merge(x, y);
                    used[i] = true;
                    total_cost += c[i];
                    total_dis -= w[i];
                }
            }
        }
    }

    cout << total_dis << '\n';
    for (int i = 1; i <= m; ++i) {
        if (used[i]) {
            cout << i << ' ';
            auto [x, y] = g[i][0];
            if (dsu.find(x) == dsu.find(y)) cout << 0;
            else cout << max(total_dis / total_cost * c[i], 0LL);
            cout << '\n';
        }
    }
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    solve();
}

