#include <iostream>
#include <string>
#include <vector>
#include <unordered_set>
#include <bitset>

using namespace std;

void evolve(string& s, int n) {
    string next = s;
    for (int i = 0; i < n; ++i) {
        int left = (i == 0 ? 0 : s[i - 1] - '0');
        int right = (i == n - 1 ? 0 : s[i + 1] - '0');
        int count = left + right;
        if ((s[i] - '0') == 0 && count == 1) {
            next[i] = '1';
        } else if ((s[i] - '0') == 1) {
            next[i] = '1';
        }
    }
    s = next;
}

bool detect_cycle(const vector<string>& states, int& start, int& len) {
    unordered_set<string> seen;
    for (int i = 0; i < states.size(); ++i) {
        if (!seen.insert(states[i]).second) {
            start = i;
            len = states.size() - i;
            return true;
        }
    }
    return false;
}

string get_final_state(int n, const string& initial, int m) {
    vector<string> states;
    states.push_back(initial);
    evolve(states.back(), n);

    bool cycle_found = false;
    int cycle_start, cycle_len;
    if (states.size() >= 2 && detect_cycle(states, cycle_start, cycle_len)) {
        cycle_found = true;
        m %= cycle_len;
    }

    if (cycle_found && m == 0) {
        return states[cycle_start];
    }

    for (int i = 0; i < m; ++i) {
        evolve(states.back(), n);
    }

    return states.back();
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int t;
    cin >> t;
    while (t--) {
        int n, m;
        cin >> n >> m;
        string initial(n, '0');
        cin >> initial;

        string result = get_final_state(n, initial, m);
        cout << result << '\n';
    }

    return 0;
}

