void solve() {
    int n, m;
    cin >> n >> m;
    vector<int> playlist(n);
    for (int i = 0; i < n; ++i) {
        cin >> playlist[i];
    }

    // Count occurrences of each band
    vector<int> count(m + 1, 0);
    for (int i : playlist) {
        count[i]++;
    }

    // Sort bands by their occurrence count
    vector<pair<int, int>> bands(m + 1);
    for (int i = 1; i <= m; ++i) {
        bands[i].first = count[i];
        bands[i].second = i;
    }
    sort(bands.begin() + 1, bands.end());

    // Distribute songs to minimize the maximum frequency
    vector<int> new_playlist(n);
    vector<int> used(m + 1, 0);
    int changes = 0;

    for (int i = 0; i < n; ++i) {
        int band = playlist[i];
        int target_band = bands[m - used[band]].second;
        if (target_band != band) {
            changes++;
        }
        new_playlist[i] = target_band;
        used[target_band]++;
    }

    // Find the minimum frequency
    int min_freq = *max_element(used.begin() + 1, used.end());
    cout << min_freq << " " << changes << endl;
    for (int song : new_playlist) {
        cout << song << " ";
    }
}

