void solve(int n, vector<int>& divisors) {
    unordered_set<int> common;

    // Step 1: Identify common divisors
    for (int i = 0; i < n; ++i) {
        for (int j = i + 1; j < n; ++j) {
            if (divisors[i] == divisors[j]) {
                common.insert(divisors[i]);
                break;
            }
        }
    }

    // Step 2: Separate the list into two parts: common and non-common
    vector<int> x_divisors, y_divisors;
    for (int d : divisors) {
        if (common.count(d)) {
            x_divisors.push_back(d);
            y_divisors.push_back(d);
        } else {
            if (x_divisors.empty()) {
                x_divisors.push_back(d);
            } else {
                y_divisors.push_back(d);
            }
        }
    }

    // Step 3: Sort and output the results
    sort(x_divisors.begin(), x_divisors.end());
    sort(y_divisors.begin(), y_divisors.end());
    cout << x_divisors.front() * x_divisors.back() << " " << y_divisors.front() * y_divisors.back() << endl;
}

