using namespace std;

bool dfs(const vector<int>& digits, int index, vector<bool>& used, long long num) {
    if (index == digits.size()) {
        return num % 7 == 0;
    }
    bool has_non_zero = false;
    for (int i = 0; i < digits.size(); ++i) {
        if (!used[i]) {
            if (!has_non_zero && digits[i] == 0) continue;
            used[i] = true;
            if (dfs(digits, index + 1, used, num * 10 + digits[i])) {
                return true;
            }
            used[i] = false;
            has_non_zero = true;
        }
    }
    return false;
}

string solve(string& s) {
    set<int> uniqueDigits;
    for (char c : s) {
        uniqueDigits.insert(c - '0');
    }

    vector<int> digits(uniqueDigits.begin(), uniqueDigits.end());
    sort(digits.begin(), digits.end());

    vector<bool> used(digits.size(), false);
    long long result = 0;
    if (dfs(digits, 0, used, result)) {
        return to_string(result);
    } else {
        return "0";
    }
}

