int minProblems(const vector<int>& skills) {
    int n = skills.size();
    map<int, int> skillFreq;

    // Count frequency of each skill
    for (int skill : skills) {
        skillFreq[skill]++;
    }

    int totalProblems = 0;

    // Calculate the minimum problems needed for each skill group
    for (const auto& entry : skillFreq) {
        int freq = entry.second;
        if (freq % 2 != 0) {
            totalProblems += freq - (freq / 2);
        }
    }

    return totalProblems;
