int solve(vector<int>& a) {
    int n = a.size();

    // Sort the array
    sort(a.begin(), a.end());

    // Find the gaps between consecutive elements
    vector<int> gaps;
    for (int i = 1; i < n; ++i) {
        gaps.push_back(a[i] - a[i-1]);
    }

    // Add the gap between the last element and infinity (n+1)
    gaps.push_back(n + 1);

    // Set to store unique gaps
    set<int> unique_gaps(gaps.begin(), gaps.end());

    // The smallest missing positive integer is the minimum gap size plus one
    int mex_of_mex = *unique_gaps.begin();

    return mex_of_mex;
