ll uc[maxn];

ll get(ll x) {
    if (x == u[x]) return x;
    return u[x] = get(u[x]);
}

void uni(ll x, ll y) {
    if (rand() % 2)
        swap(x, y);
    x = get(x), y = get(y);
    if (x == y) return;
    uc[y] += uc[x];
    u[x] = y;
}

