        dfs0(G[x][i], x);
    }
}

ll dfs(ll x, ll p = -1) {
    ll res = val[x];
    for (ll i = 0; i < sz(G[x]); ++i) {
        if (G[x][i] == p) continue;
        ll t = dfs(G[x][i], x);
        ll cur = t * (sum - t);
        if (cur > opt) {
            opt = cur;
            cnt.clear();
            cnt.pb(Gind[x][i]);
        } else if (cur == opt) {
            cnt.pb(Gind[x][i]);
        }
        res += t;
    }
