        g[x].pb({y, z});
        g[y].pb({x, z});
        gind[x].pb(i);
        gind[y].pb(i);
        v.pb(z);
        e.pb({{z, i}, {x, y}});
    }

    sort(all(v));
    v.erase(unique(all(v)), v.end());

    for (ll i = 0; i < n; ++i)
        for (ll j = 0; j < sz(g[i]); ++j) {
            ll l = g[i][j].second;
            l = lower_bound(all(v), l) - v.begin();
