const int MOD = 1e9 + 7;
const int MAXN = 100005;

vector<int> adj[MAXN];
int dp[MAXN][MAXN];

void dfs(int node, int parent, vector<long long>& weights, int& idx) {
    dp[node][weights[idx]]++;
    idx++;
    for (int next : adj[node]) {
        if (next != parent) {
            dfs(next, node, weights, idx);
        }
    }
}

long long query_path(int u, int v, vector<long long>& weights) {
    long long res = 0;
    while (u != v) {
        if (adj[u].size() > adj[v].size()) {
            swap(u, v);
        }
        for (int next : adj[u]) {
            if (next == v) {
                continue;
            }
            int w = weights.size();
            dfs(v, -1, weights, w);
            for (int i = 0; i <= w; ++i) {
                res += dp[next][i] * dp[u][weights[w] ^ i];
                res %= MOD;
            }
            break;
        }
        u = v;
    }
    return res;
}

int main() {
    ios::sync_with_stdio(false); cin.tie(nullptr);

