        adj[u].push_back(v);
        adj[v].push_back(u);
        edges[i] = {t, u, v};
    }

    // Preprocess all components
    vector<long long> weights;
    for (int i = 1; i <= n; ++i) {
        if (!adj[i].empty()) {
            weights.clear();
            dfs(i, -1, weights, 0);
            for (auto& e : edges) {
