using namespace std;

pair<int, int> simulateGame(int a, int b, const vector<pair<int, int>>& chips, const vector<pair<char, int>>& moves) {
    set<pair<int, int>> chipSet(chips.begin(), chips.end());
    int aliceScore = 0, bobScore = 0;
    bool aliceTurn = true;

    for (const auto& move : moves) {
        char c = move.first;
        int k = move.second;

        if (aliceTurn) {
            aliceTurn = false;
        } else {
            aliceTurn = true;
        }

        if (c == 'U') {
            for (int i = 0; i < k; ++i) {
                for (int j = 1; j <= b; ++j) {
                    if (chipSet.find({a - i, j}) != chipSet.end()) {
                        chipSet.erase({a - i, j});
                        if (aliceTurn) {
                            aliceScore++;
                        } else {
                            bobScore++;
                        }
                    }
                }
            }
            a -= k;
        } else if (c == 'D') {
            for (int i = 0; i < k; ++i) {
                for (int j = 1; j <= b; ++j) {
                    if (chipSet.find({i + 1, j}) != chipSet.end()) {
                        chipSet.erase({i + 1, j});
                        if (aliceTurn) {
                            aliceScore++;
                        } else {
                            bobScore++;
                        }
                    }
                }
            }
            a -= k;
        } else if (c == 'L') {
            for (int i = 0; i < k; ++i) {
                for (int j = 1; j <= a; ++j) {
                    if (chipSet.find({j, b - i}) != chipSet.end()) {
                        chipSet.erase({j, b - i});
                        if (aliceTurn) {
                            aliceScore++;
                        } else {
                            bobScore++;
                        }
                    }
                }
            }
            b -= k;
        } else if (c == 'R') {
            for (int i = 0; i < k; ++i) {
                for (int j = 1; j <= a; ++j) {
                    if (chipSet.find({j, i + 1}) != chipSet.end()) {
                        chipSet.erase({j, i + 1});
                        if (aliceTurn) {
                            aliceScore++;
                        } else {
                            bobScore++;
                        }
                    }
                }
            }
            b -= k;
        }
    }

    return {aliceScore, bobScore};
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);

    int t;
