int changeTo0(ll x) {
    ostringstream os;
    os << x;
    string s = os.str();
    return s.size() - count(s.begin(), s.end(), '0');
}

ll A, B;

ll solveA(ll a, int k) {
    ll ret = 0;
    if (k <= 0) {
        return a;
    }
    if (k <= 15) {
        ll tmp = a / TEN[k - 1];
        ret += tmp;
    }
    return ret;
}

ll solveAB(ll a, ll b, int k) {
    ll ret = 0;
    if (k <= 0) {
        return a * B + b;
    }
    if (k <= 15) {
        ll tmp = (B - 1) / TEN[k - 1];
        ret += tmp * a;
        tmp = b / TEN[k - 1];
        ret += tmp;
    }
    int dk = changeTo0(B - 1);
    ret += solveA(a, k - dk);
    return ret;
}

void solve() {
    int K;
