    cin >> h >> m >> k;
    int h1, m1;
    cin >> h1 >> m1;
    int h2, m2;
    cin >> h2 >> m2;

    // Calculate digit counts for h-1 and m-1
    int digits_h = to_string(h-1).size();
    int digits_m = to_string(m-1).size();

    long long count = 0;

    // Helper function to get string representations of current and next minute
    auto get_time_str = [&](int hh, int mm) {
        string s_h = to_string(hh);
        string s_m = to_string(mm);
        while (s_h.size() < digits_h) s_h = '0' + s_h;
        while (s_m.size() < digits_m) s_m = '0' + s_m;
        return make_pair(s_h, s_m);
    };

    // Iterate over each minute in the range [h1:m1, h2:m2]
    for (int i = h1; i <= h2 || (i == h2 && m1 <= m2); ++i) {
        for (int j = m1; j <= m2; ++j) {
            auto current = get_time_str(i, j);
            auto next = get_time_str((i == h2 && j == m2) ? 0 : i+(j==m2), (j+1)%m);

            int diff = 0;
            for (int d = 0; d < digits_h; ++d) {
                if (current.first[d] != next.first[d]) diff++;
            }
            for (int d = 0; d < digits_m; ++d) {
                if (current.second[d] != next.second[d]) diff++;
            }

            if (diff >= k) count++;
        }
        m1 = 0;  // Reset minutes to start of new hour
    }

    cout << count << '\n';
    return 0;
}

