#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

long long solve(int n, vector<int>& a, const vector<int>& B) {
    vector<int> neg_indices;
    for (int i = 0; i < n; ++i) {
        if (a[i] < 0) neg_indices.push_back(i);
    }

    sort(B.begin(), B.end(), greater<int>());

    int idx = 0;
    while (!neg_indices.empty()) {
        bool flipped = false;
        for (int x : B) {
            if (idx + x > neg_indices.size()) continue;
            bool found = false;
            int min_neg_index = INT_MAX;
            for (int i = idx; i < idx + x; ++i) {
                if (a[neg_indices[i]] < 0 && neg_indices[i] < min_neg_index) {
                    min_neg_index = neg_indices[i];
                    found = true;
                }
            }
            if (found) {
                for (int i = idx; i < idx + x; ++i) {
                    a[neg_indices[i]] *= -1;
                }
                neg_indices.erase(find(neg_indices.begin(), neg_indices.end(), min_neg_index));
                idx += x;
                flipped = true;
                break;
            }
        }
        if (!flipped) break;
    }

    return accumulate(a.begin(), a.end(), 0LL);
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int t;
    cin >> t;
    while (t--) {
        int n, m;
        cin >> n >> m;
        vector<int> a(n), B(m);
        for (int i = 0; i < n; ++i) cin >> a[i];
        for (int i = 0; i < m; ++i) cin >> B[i];

        cout << solve(n, a, B) << '\n';
    }

    return 0;
}

