ll rec(vll &indices, vll &sorted_x, vll &sorted_y) {
    ll sz = indices.size();
    if (sz <= 1) return 1;

    ll lx = 0, rx = sz - 1;
    ll ly = 0, ry = sz - 1;

    bool found = false;
    ll split_dim = 0;
    ll split_val = 0;
    ll left_size = 0;

    while (lx <= rx || ly <= ry) {
        if (lx < sz - 1 && lx + 1 <= rx) {
            ll i1 = sorted_x[lx];
            ll i2 = sorted_x[lx + 1];
            if (pts[i2].x - pts[i1].x >= 2) {
                found = true;
                split_dim = 0;
                split_val = pts[i1].x + 1;
                left_size = lx + 1;
                break;
            }
        }
        if (rx > 0 && rx - 1 >= lx) {
            ll i1 = sorted_x[rx - 1];
            ll i2 = sorted_x[rx];
            if (pts[i2].x - pts[i1].x >= 2) {
                found = true;
                split_dim = 0;
                split_val = pts[i1].x + 1;
                left_size = rx;
                break;
            }
        }
        if (ly < sz - 1 && ly + 1 <= ry) {
            ll i1 = sorted_y[ly];
            ll i2 = sorted_y[ly + 1];
            if (pts[i2].y - pts[i1].y >= 2) {
                found = true;
                split_dim = 1;
                split_val = pts[i1].y + 1;
                left_size = ly + 1;
                break;
            }
        }
        if (ry > 0 && ry - 1 >= ly) {
            ll i1 = sorted_y[ry - 1];
            ll i2 = sorted_y[ry];
            if (pts[i2].y - pts[i1].y >= 2) {
                found = true;
                split_dim = 1;
                split_val = pts[i1].y + 1;
                left_size = ry;
                break;
            }
        }

        if (lx <= rx) {
            lx++;
            rx--;
        }
        if (ly <= ry) {
            ly++;
            ry--;
        }
        if (lx > rx && ly > ry) break;
    }

    if (!found) {
        return 1;
    }

    vll small_indices, large_indices;
    vll small_sx, small_sy, large_sx, large_sy;

    bool left_is_smaller = (left_size <= sz - left_size);

    if (split_dim == 0) {
        if (left_is_smaller) {
            small_indices.assign(sorted_x.begin(), sorted_x.begin() + left_size);
            large_indices.assign(sorted_x.begin() + left_size, sorted_x.end());
        } else {
            small_indices.assign(sorted_x.begin() + left_size, sorted_x.end());
            large_indices.assign(sorted_x.begin(), sorted_x.begin() + left_size);
