using namespace std;

class UnionFind {
public:
    vector<int> parent;
    vector<int> size;
    int num_components;

    UnionFind(int n) : parent(n), size(n, 1), num_components(n) {
        for (int i = 0; i < n; ++i) {
            parent[i] = i;
        }
    }

    int find(int u) {
        if (parent[u] == u) return u;
        return parent[u] = find(parent[u]);
    }

    void unite(int u, int v) {
        int pu = find(u);
        int pv = find(v);
        if (pu != pv) {
            if (size[pu] > size[pv]) {
                swap(pu, pv);
            }
            parent[pu] = pv;
            size[pv] += size[pu];
            --num_components;
        }
    }
};

bool areConnected(vector<int>& p1, vector<int>& p2) {
    return p1[0] == p2[0] || p1[1] == p2[1];
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;
    vector<vector<int>> points(n, vector<int>(2));
    unordered_map<long long, int> indexMap;

    for (int i = 0; i < n; ++i) {
        cin >> points[i][0] >> points[i][1];
        long long hash = static_cast<long long>(points[i][0]) * 1000000000 + points[i][1];
        indexMap[hash] = i;
    }

    UnionFind uf(n);

    for (int i = 0; i < n; ++i) {
        for (int j = i + 1; j < n; ++j) {
            if (areConnected(points[i], points[j])) {
                uf.unite(i, j);
            }
        }
    }

    cout << uf.num_components << endl;

    return 0;
}

