void solve(int n, const string& s) {
    vector<int> arr(n);
    set<int> used;
    int current_min = 1;

    for (int i = 0; i < n - 1; ++i) {
        if (s[i] == '<') {
            // Find the smallest unused number greater than current_min
            int next = *used.upper_bound(current_min);
            arr[i] = next;
            used.insert(next);
            current_min = next + 1;
        } else { // s[i] == '>'
            // Find the largest unused number less than current_max
            auto it = used.lower_bound(1);
            if (it != used.end()) --it;
            int prev = *it;
            arr[i] = prev;
            used.erase(prev);
        }
    }

    // Place the last remaining number
    arr[n-1] = *used.begin();

    for (int num : arr) cout << num << " ";
    cout << endl;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int t;
    cin >> t;
    while (t--) {
        int n;
        cin >> n;
        string s;
        cin >> s;
        solve(n, s);
    }
    return 0;
}

