long long minMoves(long long n, unordered_map<long long, long long>& memo) {
    if (memo.find(n) != memo.end()) return memo[n];
    if (n == 1) return 0;
    if (n % 6 != 0 && n % 2 != 0) return -1;

    long long res = -1;
    if (n % 6 == 0) {
        long long divBy6 = n / 6;
        long long mulBy2 = n * 2;
        if (divBy6 <= 1000000) {
            long long val = minMoves(divBy6, memo);
            if (val != -1) {
                res = val + 1;
            }
        }
        if (mulBy2 <= 1000000) {
            long long val = minMoves(mulBy2, memo);
            if (res == -1 || (val != -1 && val + 1 < res)) {
                res = val + 1;
            }
        }
    } else if (n % 2 == 0) {
        long long mulBy2 = n * 2;
        if (mulBy2 <= 1000000) {
            long long val = minMoves(mulBy2, memo);
            if (val != -1) {
                res = val + 1;
            }
