ll gcd(ll a, ll b) {
    while (a > 0) {
        ll temp = b % a;
        b = a;
        a = temp;
    }
    return b;
}

ll lcm(ll a, ll b) {
    return a / gcd(a, b) * b;
}

ll ceildiv(ll n, ll k) {
    ll t = n / k;
    if (n % k == 0) return t;
    return t + 1;
}

ll pw(ll a, ll b) {
    ll r = 1;
    while (b) {
        if (b & 1) r *= a;
        a *= a;
        b >>= 1;
    }
    return r;
}

ll modpw(ll a, ll b, ll mod) {
    ll r = 1 % mod;
    a %= mod;
    while (b) {
        if (b & 1) r = r * a % mod;
        a = a * a % mod;
        b >>= 1;
    }
    return r;
}

// helper: none needed beyond the wrapper

void solve() {
    const ll NEG_INF = -1e18;

    int n, k;
    cin >> n >> k;

    vector<vll> pref(n);
    vll t(n);
    vll full_val(n, NEG_INF);
    vll full_w(n, 0);

    for (int i = 0; i < n; ++i) {
        cin >> t[i];
        int sz = t[i];
        pref[i].resize(min(sz, k) + 1, 0);
        ll sum = 0;
        for (int j = 1; j <= min(sz, k); ++j) {
            int x;
            cin >> x;
            sum += x;
            pref[i][j] = sum;
        }
        // skip remaining elements if sz > k
        for (int j = min(sz, k) + 1; j <= sz; ++j) {
            int x;
            cin >> x;
        }
        if (sz <= k) {
            full_val[i] = pref[i][sz];
            full_w[i] = sz;
        }
    }

    ll ans = 0;

    // dp array for knapsack
    vll dp(k + 1, NEG_INF);
    dp[0] = 0;

    // divide and conquer
    function<void(int, int, vll&)> go = [&](int l, int r, vll& cur_dp) {
        if (l == r) {
            // array l is the partial one
            int idx = l;
            int sz = t[idx];
            int max_prefix = min(sz, k);
            for (int w = max(0, k - max_prefix); w <= k; ++w) {
                if (cur_dp[w] == NEG_INF) continue;
                int rem = k - w;
                ll cand = cur_dp[w] + pref[idx][rem];
                if (cand > ans) ans = cand;
            }
            return;
        }
        int mid = (l + r) / 2;

        // go right: add left half to dp
        vll dp_left = cur_dp;
        for (int i = l; i <= mid; ++i) {
            if (full_val[i] == NEG_INF) continue;
            int w = full_w[i];
            ll v = full_val[i];
            for (int j = k; j >= w; --j) {
                if (dp_left[j - w] != NEG_INF) {
                    dp_left[j] = max(dp_left[j], dp_left[j - w] + v);
                }
            }
        }
        go(mid + 1, r, dp_left);

        // go left: add right half to dp
        vll dp_right = cur_dp;
        for (int i = mid + 1; i <= r; ++i) {
            if (full_val[i] == NEG_INF) continue;
            int w = full_w[i];
            ll v = full_val[i];
            for (int j = k; j >= w; --j) {
                if (dp_right[j - w] != NEG_INF) {
                    dp_right[j] = max(dp_right[j], dp_right[j - w] + v);
                }
            }
        }
        go(l, mid, dp_right);
    };

    go(0, n - 1, dp);

    cout << ans << endl;
}

