    vector<vector<int>> arrays(n);
    for (int i = 0; i < n; ++i) {
        cin >> sizes[i];
        arrays[i].resize(sizes[i]);
        for (int j = 0; j < sizes[i]; ++j) {
            cin >> arrays[i][j];
        }
    }

    // Max-heap to store (-value, array_index, element_index)
    priority_queue<pair<int, pair<int, int>>> pq;
    for (int i = 0; i < n; ++i) {
        if (!arrays[i].empty()) {
            pq.push({-arrays[i][0], {i, 0}});
        }
    }

    long long sum = 0;
    while (k > 0 && !pq.empty()) {
        auto [val, idx] = pq.top();
        pq.pop();

        sum -= val; // Convert back to positive
        --sizes[idx.first];

        if (sizes[idx.first] > 0) {
            pq.push({-arrays[idx.first][idx.second + 1], {idx.first, idx.second + 1}});
        }

        --k;
    }

    cout << sum << endl;
    return 0;
}

