const int MAX_N = 1000000;
int spf[MAX_N + 1];

void sieveOfEratosthenes(int maxN) {
    fill(spf, spf + maxN + 1, -1);
    for (int i = 2; i <= maxN; ++i) {
        if (spf[i] == -1) {
            spf[i] = i;
            for (int j = i * 2; j <= maxN; j += i) {
                if (spf[j] == -1)
                    spf[j] = i;
            }
        }
    }
}

int solve(int n, int k) {
    while (k--) {
        n += spf[n];
    }
    return n;
}

