void solve(int n, vector<pair<int, int>>& edges) {
    vector<vector<int>> adj(n + 1);
    for (auto& e : edges) {
        adj[e.first].push_back(e.second);
        adj[e.second].push_back(e.first);
    }

    bool drawn[n + 1];
    fill(drawn, drawn + n + 1, false);
    drawn[1] = true;
    queue<int> q;
    q.push(1);

    int readings = 0;
    while (!q.empty()) {
        int size = q.size();
        bool new_drawn = false;
        for (int i = 0; i < size; ++i) {
            int u = q.front(); q.pop();
            for (int v : adj[u]) {
                if (!drawn[v]) {
                    drawn[v] = true;
                    q.push(v);
                    new_drawn = true;
                }
            }
        }
        if (new_drawn) {
            ++readings;
        } else {
            break;
        }
    }

    cout << readings << endl;
}

