vector<string> distribution(map<string,int>& available, const vector<string>& wish) {
    vector<string> double_keys = {"S,M", "M,L", "L,XL", "XL,XXL", "XXL,XXXL"};
    unordered_map<string, vector<int>> double_map;
    vector<string> people(wish.size());
    for (int i = 0; i < (int)wish.size(); ++i) {
        string w = wish[i];
        if (w.find(',') == string::npos) {
            if (available[w] > 0) {
                available[w]--;
                people[i] = w;
            } else {
                return {"NO"};
            }
        } else {
            double_map[w].pb(i);
        }
    }
    for (auto& key : double_keys) {
        for (int p : double_map[key]) {
            bool lack = true;
            istringstream iss(key);
            string size;
            while (getline(iss, size, ',')) {
                if (available[size] > 0) {
                    available[size]--;
                    people[p] = size;
                    lack = false;
                    break;
                }
            }
            if (lack) {
                return {"NO"};
            }
        }
    }
    vector<string> ans;
    ans.pb("YES");
    for (auto& p : people) ans.pb(p);
    return ans;
}

