using namespace std;

bool canAssign(vector<int>& counts, vector<string>& prefs) {
    int n = prefs.size();
    vector<int> direct(6, 0);
    vector<vector<int>> pairs(n, vector<int>(2));

    // Count direct requests and parse pair requests
    for (int i = 0; i < n; ++i) {
        if (prefs[i].find(',') != string::npos) {
            pairs[i][0] = prefs[i][0];
            pairs[i][1] = prefs[i][2];
        } else {
            direct[prefs[i][0] - 'A']++;
        }
    }

    // Check direct assignments
    for (int i = 0; i < 6; ++i) {
        if (direct[i] > counts[i]) return false;
        counts[i] -= direct[i];
    }

    // Assign pairs
    for (int i = 0; i < n; ++i) {
        int a = pairs[i][0], b = pairs[i][1];
        if (a == b || counts[a] > 0) {
            if (counts[a] > 0) --counts[a];
            else --counts[b];
        } else {
            if (counts[b] > 0) --counts[b];
            else return false;
        }
    }

    return true;
}

void assign(vector<int>& counts, vector<string>& prefs, vector<char>& result) {
    int n = prefs.size();
    vector<int> direct(6, 0);
    vector<vector<int>> pairs(n, vector<int>(2));

    for (int i = 0; i < n; ++i) {
        if (prefs[i].find(',') != string::npos) {
            pairs[i][0] = prefs[i][0];
            pairs[i][1] = prefs[i][2];
        } else {
            direct[prefs[i][0] - 'A']++;
        }
    }

    for (int i = 0; i < 6; ++i) {
        for (int j = 0; j < direct[i]; ++j) {
            result.push_back('A' + i);
        }
    }

    for (int i = 0; i < n; ++i) {
        int a = pairs[i][0], b = pairs[i][1];
        if (counts[a] > 0) {
            result.push_back(a);
            --counts[a];
        } else {
            result.push_back(b);
            --counts[b];
        }
    }
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);

    vector<int> counts(6);
    for (int i = 0; i < 6; ++i) cin >> counts[i];

    int n;
    cin >> n;
    vector<string> prefs(n);
    for (int i = 0; i < n; ++i) cin >> prefs[i];

    if (!canAssign(counts, prefs)) {
        cout << "NO\n";
        return 0;
    }

    vector<char> result;
    assign(counts, prefs, result);
    cout << "YES\n";
    for (char c : result) cout << c << '\n';

    return 0;
}

