// Function to find the smallest non-trivial divisor of n
ll smallest_non_trivial_divisor(ll n) {
    for (ll i = 2; i * i <= n; ++i) {
        if (n % i == 0) return i;
    }
    return n; // n is prime
}

// Function to determine the winner for a given number q
pair<int, int> determine_winner(ll q) {
    if (q == 1) return {1, 0}; // First player loses
    if (smallest_non_trivial_divisor(q) != q) { // q is composite
        ll d = smallest_non_trivial_divisor(q);
        auto [winner, move] = determine_winner(d);
        if (winner == 1) return {2, d}; // Opponent lost, first player wins
        else return {1, 0}; // Opponent won, first player loses
    } else { // q is prime
        return {1, 0}; // First player loses
    }
}

