#include <queue>
#include <utility>

using namespace std;

void solve(int n, const vector<vector<int>>& edges) {
    vector<vector<int>> adj(n + 1);
    vector<int> degree(n + 1);

    // Build adjacency list and degree array
    for (const auto& e : edges) {
        int u = e[0], v = e[1];
        adj[u].push_back(v);
        adj[v].push_back(u);
        degree[u]++;
        degree[v]++;
    }

    // Min-heap to store vertices by their degree
    priority_queue<pair<int, int>, vector<pair<int, int>>, greater<pair<int, int>>> pq;
    for (int i = 1; i <= n; ++i) {
        pq.push({degree[i], i});
    }

    int components = 1;
    while (!pq.empty()) {
        auto [d, v] = pq.top();
        pq.pop();

        if (d == 0) {
            continue;
        }

        --components;
        for (int neighbor : adj[v]) {
            if (--degree[neighbor] == 1) {
                pq.push({1, neighbor});
            }
        }
    }

    cout << components << endl;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int t;
    cin >> t;
    while (t--) {
        int n;
        cin >> n;
        vector<vector<int>> edges(n - 1, vector<int>(2));
        for (int i = 0; i < n - 1; ++i) {
            cin >> edges[i][0] >> edges[i][1];
        }
        solve(n, edges);
    }

    return 0;
}

