void bfs(int start, int target_dist, vector<int>& level, int dist) {
    queue<int> q;
    q.push(start);
    visited[start] = true;
    level[start] = 0;

    while (!q.empty()) {
        int node = q.front();
        q.pop();

        for (int neighbor : adj[node]) {
            if (!visited[neighbor]) {
                visited[neighbor] = true;
                level[neighbor] = level[node] + 1;
                q.push(neighbor);

                if (level[neighbor] == target_dist) {
