struct Coupon {
    int l, r;
    bool operator<(const Coupon& other) const {
        return l < other.l;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n, k;
    cin >> n >> k;

    vector<Coupon> coupons(n);
    for (int i = 0; i < n; ++i) {
        cin >> coupons[i].l >> coupons[i].r;
    }

    sort(coupons.begin(), coupons.end());

    auto intersectionSize = [](const vector<Coupon>& window) {
        int maxL = INT_MAX;
        int minR = INT_MIN;
        for (const auto& c : window) {
            maxL = max(maxL, c.l);
            minR = min(minR, c.r);
        }
        if (maxL <= minR) {
            return minR - maxL + 1;
        }
        return 0;
    };

    priority_queue<pair<int, int>> pq; // (-size, index)
    vector<bool> used(n, false);
    int currentSize = 0;
    for (int i = 0; i < k; ++i) {
        while (!pq.empty() && pq.top().second < i - k + 1) {
            pq.pop();
        }
        used[i] = true;
        currentSize += coupons[i].r - coupons[i].l + 1;
        pq.push({-(coupons[i].r - coupons[i].l + 1), i});
    }

    int bestSize = currentSize;
    int bestStart = 0;

    for (int i = k; i < n; ++i) {
        while (!pq.empty() && pq.top().second < i - k + 1) {
            pq.pop();
        }
        currentSize -= coupons[i - k].r - coupons[i - k].l + 1;
        currentSize += coupons[i].r - coupons[i].l + 1;
        pq.push({-(coupons[i].r - coupons[i].l + 1), i});

        int size = intersectionSize(pq);
        if (size > bestSize) {
            bestSize = size;
            bestStart = i - k + 1;
        }
    }

    cout << bestSize << '\n';
    for (int i = bestStart; i < bestStart + k; ++i) {
        cout << i + 1 << ' ';
    }
    cout << '\n';

    return 0;
}

