    string right = initial.substr(pos + 1);

    unordered_set<char> used_left(left.begin(), left.end());
    unordered_set<char> used_right(right.begin(), right.end());

    int sum_left = 0;
    int sum_right = 0;

    for (char c : left) sum_left += c - 'A' + 1;
    for (char c : right) sum_right += c - 'A' + 1;

    if (sum_left == sum_right) {
        cout << left << '|' << right << endl;
        return;
