#include <iostream>
#include <vector>
#include <queue>
#include <algorithm>

using namespace std;

struct Event {
    int time;
    bool isStart;
};

bool compareEvents(const Event& a, const Event& b) {
    if (a.time == b.time) {
        return a.isStart > b.isStart; // Process ends before starts
    }
    return a.time < b.time;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;

    vector<Event> events(2 * n);
    for (int i = 0; i < n; ++i) {
        int l, r;
        cin >> l >> r;
        events[i * 2] = {l, true};
        events[i * 2 + 1] = {r, false};
    }

    sort(events.begin(), events.end(), compareEvents);

    priority_queue<int, vector<int>, greater<int>> pq; // Min-heap for active show indices
    bool tv1Available = true, tv2Available = true;

    for (const auto& event : events) {
        if (event.isStart) {
            if (!pq.empty()) {
                int index = pq.top();
                pq.pop();
                if (index % 2 == 0 && tv1Available) {
                    tv1Available = false;
                    pq.push(index + 1); // Mark as used by TV1
                } else if (tv2Available) {
                    tv2Available = false;
                    pq.push(index + 2); // Mark as used by TV2
                } else {
                    cout << "NO" << endl;
                    return 0;
                }
            } else {
                if (tv1Available) {
                    tv1Available = false;
                    pq.push(event.time); // Mark as used by TV1
                } else if (tv2Available) {
                    tv2Available = false;
                    pq.push(event.time + 1); // Mark as used by TV2
                } else {
                    cout << "NO" << endl;
                    return 0;
                }
            }
        } else {
            int index = pq.top();
            pq.pop();
            if (index % 2 == 0) {
                tv1Available = true;
            } else {
                tv2Available = true;
            }
        }
    }

    cout << "YES" << endl;
    return 0;
}

