int maxScore(vector<vector<int>>& grid, int k) {
    int n = grid.size();
    int m = grid[0].size();
    vector<pair<int, int>> topmost(n);

    // Find topmost 1 in each column
    for (int col = 0; col < m; ++col) {
        for (int row = 0; row < n; ++row) {
            if (grid[row][col] == 1) {
                topmost[col] = {row, col};
                break;
            }
        }
    }

    int score = 0;
    int replacements = 0;

    for (const auto& [row, col] : topmost) {
        if (row != -1) {
            int countOnes = 0;
            for (int i = row; i < min(row + k, n); ++i) {
                if (grid[i][col] == 1) {
                    countOnes++;
                } else {
                    replacements++;
                }
            }
            score += countOnes;
        }
    }

    return score;
}

