const int N = 404;

int n, m;
string s[404];
int pref[3][404][404];

int whattp(char ch) {
    if (ch == '.') return 0;
    if (ch == 'm') return 1;
    return 2;
}

int withM[404][N], withoutM[404][N];
int withHor[404][404];
int withoutHor[404][404];

int get(int tp, int ax, int ay, int bx, int by) {
    --ax, --ay;
    return pref[tp][bx][by] + pref[tp][ax][ay] - pref[tp][ax][by] - pref[tp][bx][ay];
}

void solve() {
    cin >> n >> m;
    for (int i = 1; i <= n; ++i) {
        cin >> s[i];
        s[i] = '#' + s[i];
    }

    for (int tp = 0; tp < 3; ++tp) {
        for (int i = 1; i <= n; ++i) {
            for (int j = 1; j <= m; ++j) {
                pref[tp][i][j] -= pref[tp][i - 1][j - 1];
                pref[tp][i][j] += pref[tp][i - 1][j];
                pref[tp][i][j] += pref[tp][i][j - 1];
                if (tp == whattp(s[i][j])) {
                    pref[tp][i][j]++;
                }
            }
        }
    }

    for (int j = 1; j <= m; ++j) {
        int last = 0;
        for (int i = 1; i <= n; ++i) {
            withM[i][j] = withM[i - 1][j];
            withoutM[i][j] = withoutM[i - 1][j];

            if (s[i][j] == '#') {
                withM[i][j] = withoutM[i][j] = i;
            }
            if (s[i][j] == 'm') {
                withoutM[i][j] = i;
                withM[i][j] = max(withM[i][j], last);
                last = i;
            }
        }
    }

    int ans = 0;

    for (int i = 1; i < m - 1; ++i) {
        for (int j = i + 2; j <= m; ++j) {
            for (int bottom = 1; bottom <= n; ++bottom) {
                if (s[bottom][i] == '#') continue;
                if (s[bottom][j] == '#') continue;

                {
                    int len = bottom - max(withoutM[bottom][i], withM[bottom][j]);
                    if (len >= 3 && withoutHor[i][j] > bottom - len + 1) {
                        ans = max(ans, len * 2 + (j - i - 1));
