                if (get(2, bottom, i + 1, bottom, j - 1) > 0) continue;
                if (get(1, bottom, i + 1, bottom, j - 1) > 1) continue;
                if (get(1, bottom, i + 1, bottom, j - 1) == 1) {
                    withHor[i][j] = bottom;
                    continue;
                }
                withHor[i][j] = bottom;
                withoutHor[i][j] = bottom;
            }
        }
    }

