    for (int col1 = 0; col1 < m; ++col1) {
        for (int col2 = col1 + 2; col2 < m; ++col2) {
            bool valid_horizontal = false;
            int perfect_count = 0;
            int medium_count = 0;

            // Check all rows between col1 and col2
            for (int row = 0; row < n; ++row) {
                if (grid[row][col1] == '#' || grid[row][col2] == '#') {
                    continue;
                }

                if (grid[row][col1] == '.') {
                    ++perfect_count;
                } else if (grid[row][col1] == 'm') {
                    ++medium_count;
                }

                if (grid[row][col2] == '.') {
                    ++perfect_count;
                } else if (grid[row][col2] == 'm') {
                    ++medium_count;
                }

                // Check if the current row can host the horizontal line
                if (row > 0 && row < n - 1) {
                    valid_horizontal = true;
                }
            }

            if (valid_horizontal) {
                max_walls = max(max_walls, perfect_count + min(1, medium_count));
            }
        }
    }

