void solve(int n, int k) {
    vector<int> a(n);
    int pos = 31;

    // Distribute bits from MSB to LSB
    while (pos >= 0 && k > 0) {
        int cnt = min(n, k);
        for (int i = 0; i < cnt; ++i) {
            a[i] |= (1 << pos);
        }
        k -= cnt;
        --pos;
    }

    // Distribute remaining k
    for (int i = 0; i < n && k > 0; ++i) {
        if (a[i] == 0) {
            a[i] = k;
            k = 0;
        } else {
            break;
        }
    }

    // Output the sequence
    for (int i = 0; i < n; ++i) {
        if (i > 0) cout << " ";
