#include <iostream>
#include <vector>
#include <set>
using namespace std;

int solve(int a, int b) {
    vector<int> arr;
    set<int> s;
    int xor_val = 0;

    // Step 1: Add a to the array
    arr.push_back(a);
    s.insert(a);
    xor_val ^= a;

    // Step 2: Add numbers from 0 to a-1
    for (int i = 0; i < a; ++i) {
        arr.push_back(i);
        s.insert(i);
        xor_val ^= i;
    }

    // Step 3: Adjust XOR to match b
    while (xor_val != b) {
        if (xor_val < b) {
            // Find a number to add that increases the XOR
            int x = *s.rbegin();
            s.erase(x);
            arr.pop_back();
            xor_val ^= x;
            arr.push_back(x + 1);
            s.insert(x + 1);
            xor_val ^= (x + 1);
        } else {
            // Find a number to remove that decreases the XOR
            int x = *s.begin();
            s.erase(x);
            arr.pop_back();
            xor_val ^= x;
        }
    }

    return arr.size();
}

