#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

using namespace std;

bool canPaintWithKStrokes(const vector<int>& a, int k) {
    int n = a.size();
    vector<int> prefix(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix[i + 1] = prefix[i] + a[i];
    }

    // Try placing k-1 dividers among n-1 gaps
    for (int d = 0; d <= n - k; ++d) {
        bool valid = true;
        for (int j = 0; j < k - 1; ++j) {
            int dividerPos = d + j * (n - k + 1) / (k - 1);
            int start = dividerPos == 0 ? 0 : dividerPos;
            int end = dividerPos + (n - k + 1) / (k - 1);
            if (end >= n) end = n - 1;
            int maxHeight = a[end];
            int segmentSum = prefix[end + 1] - prefix[start];
            if (segmentSum < maxHeight) {
                valid = false;
                break;
            }
        }
        if (valid) return true;
    }
    return false;
}

int minStrokes(vector<int>& a) {
    sort(a.begin(), a.end());
    int n = a.size();
    int low = 1, high = n, result = INT_MAX;
    while (low <= high) {
        int mid = (low + high) / 2;
        if (canPaintWithKStrokes(a, mid)) {
            result = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }
    return result;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;
    vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        cin >> a[i];
    }

    cout << minStrokes(a) << endl;

    return 0;
}

