#include <bits/stdc++.h>
using namespace std;

const int MAXN = 5e5 + 5;
vector<pair<int, char>> adj[MAXN];
int n;

// Function to convert frequency map to bitmask
int encode(unordered_map<char, int>& freq) {
    int mask = 0;
    for (auto& [ch, cnt] : freq)
        if (cnt % 2 != 0)
            mask |= 1 << (ch - 'a');
    return mask;
}

// Function to decode bitmask back to frequency map
unordered_map<char, int> decode(int mask) {
    unordered_map<char, int> freq;
    for (int i = 0; i < 26; ++i) {
        if (mask & (1 << i))
            freq['a' + i]++;
    }
    return freq;
}

// DFS function to compute frequency maps and answer
void dfs(int u, int p, vector<unordered_map<char, int>>& freqs, vector<int>& ans) {
    freqs[u] = {adj[u].begin()->second, 1};
    int best_len = 0;

    for (auto [v, ch] : adj[u]) {
        if (v == p)
            continue;

        dfs(v, u, freqs, ans);

        // Combine current node's frequency with child's frequency
        auto& parent_freq = freqs[u];
        auto& child_freq = freqs[v];

        // Compute new frequency map by adding child's frequencies
        unordered_map<char, int> combined = parent_freq;
        for (auto& [ch, cnt] : child_freq)
            combined[ch] += cnt;

        // Calculate number of characters with odd counts in combined map
        int odd_count = 0;
        for (auto& [ch, cnt] : combined)
            if (cnt % 2 != 0)
                odd_count++;

        // If at most one character has an odd count, it's palindromic
        if (odd_count <= 1) {
            best_len = max(best_len, 2 + (parent_freq.empty() ? 0 : parent_freq.begin()->second));
        } else {
            // Try removing one character from parent's side to make it palindromic
            int len_no_parent = 0;
            for (auto& [ch, cnt] : parent_freq) {
                if ((cnt - child_freq[ch]) % 2 != 0) {
                    len_no_parent = max(len_no_parent, 2 * (cnt - child_freq[ch]));
                }
            }
            best_len = max(best_len, len_no_parent);
        }
    }

    ans[u] = best_len;
}

int main() {
    ios::sync_with_stdio(false); cin.tie(0); cout.tie(0);

    cin >> n;
    for (int i = 2; i <= n; ++i) {
        int p; char c;
        cin >> p >> c;
        adj[p].emplace_back(i, c);
    }

    vector<unordered_map<char, int>> freqs(n + 1);
    vector<int> ans(n + 1);

    dfs(1, 0, freqs, ans);

    for (int i = 1; i <= n; ++i)
        cout << ans[i] << " ";

    return 0;
}

