#include <iostream>
#include <vector>
#include <algorithm>
#include <random>

using namespace std;

void solve(int n, int m, int k) {
    int base = n / m;
    int extra = n % m;

    vector<int> players(n);
    for (int i = 0; i < n; ++i) {
        players[i] = i + 1;
    }

    random_device rd;
    mt19937 g(rd());

    for (int game = 0; game < k; ++game) {
        shuffle(players.begin(), players.end(), g);

        vector<vector<int>> tables(m);
        for (int i = 0; i < m; ++i) {
            if (i < extra) {
                tables[i].resize(base + 1);
            } else {
                tables[i].resize(base);
            }
        }

        for (int i = 0; i < n; ++i) {
            int player = players[i];
            int table_index = i % m;
            tables[table_index].push_back(player);
        }

        // Rebalance player counts within the same game
        vector<int> counts(m, 0);
        for (int i = 0; i < m; ++i) {
            counts[i] = tables[i].size();
        }

        bool adjusted;
        do {
            adjusted = false;
            for (int i = 0; i < m; ++i) {
                for (int j = i + 1; j < m; ++j) {
                    if (abs(counts[i] - counts[j]) > 1) {
                        if (counts[i] > counts[j]) {
                            int move_player = tables[i].back();
                            tables[i].pop_back();
                            tables[j].push_back(move_player);
                            --counts[i];
                            ++counts[j];
                            adjusted = true;
                        } else {
                            int move_player = tables[j].back();
                            tables[j].pop_back();
                            tables[i].push_back(move_player);
                            ++counts[i];
                            --counts[j];
                            adjusted = true;
                        }
                    }
                }
            }
        } while (adjusted);

        for (int i = 0; i < m; ++i) {
            cout << tables[i].size();
            for (int player : tables[i]) {
                cout << ' ' << player;
            }
            cout << '\n';
        }
        cout << '\n';
    }
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int t;
    cin >> t;
    while (t--) {
        int n, m, k;
        cin >> n >> m >> k;
        solve(n, m, k);
    }

    return 0;
}

