#include <iostream>
#include <cmath>
using namespace std;

bool is_perfect_square(long long n) {
    long long root = sqrt(n);
    return root * root == n;
}

int min_operations(int x, int y) {
    long long dist_squared = x * x + y * y;
    if (is_perfect_square(dist_squared)) {
        return 1;
    }

    int ans = INT_MAX;
    for (int a = 0; a <= 50; ++a) {
        for (int b = 0; b <= 50; ++b) {
            long long ab_squared = a * a + b * b;
            if (!is_perfect_square(ab_squared)) continue;

            long long xy_ab_squared = (x - a) * (x - a) + (y - b) * (y - b);
            if (!is_perfect_square(xy_ab_squared)) continue;

            ans = min(ans, 2); // Two segments: (0,0) -> (a,b) -> (x,y)
        }
    }

    return ans;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int t;
    cin >> t;
    while (t--) {
        int x, y;
        cin >> x >> y;
        cout << min_operations(x, y) << endl;
    }

    return 0;
}
